import{_ as i,c as s,a as t,o as a}from"./app-CEcM0piI.js";const d={};function r(l,e){return a(),s("div",null,e[0]||(e[0]=[t(`<ul><li>ctrl+c强制停止</li><li>ctrl+d退出账户的登录或退出某些程序的专属页面（如：查询Python环境）</li><li>history命令用于查看历史输入过的命令可以配合管道符和grep过滤掉不需要查看的</li><li>！命令前缀自动执行上一次匹配的历史命令 如：以前执行过Python使用！p或！py至执行都相当于Python命令，但它是从后往前找，只匹配最新的</li><li>ctrl+r历史命令搜索，使用这个快捷键切换模式，然后输入字段从后往前搜索含有该字段的命令</li><li>ctrl+a跳到命令开头</li><li>ctrl+e跳到命令结尾</li><li>ctrl+键盘左键 向左跳一个单词</li><li>ctrl+键盘右键 向右跳一个单词</li><li>ctrl+l或clear清屏</li></ul><h2 id="yum命令" tabindex="-1"><a class="header-anchor" href="#yum命令"><span>yum命令</span></a></h2><p>rpm包软件管理器，用于自动化安装配置Linux软件，并自动解决依赖问题 需要联网和root权限 rpm是Linux系统软件安装包格式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>yum [-y] [install | remove |search] 软件名称</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-y：自动确认，无需手动确认安装或卸载过程 install：安装 remove：卸载 search：搜索</p><h2 id="systemctl命令" tabindex="-1"><a class="header-anchor" href="#systemctl命令"><span>systemctl命令</span></a></h2><p>linux系统很多软件（或第三方）均支持systemctl命令控制：启动，停止，开机自启 能被systemctl管理的软件一般称之为服务</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>systemctl start | stop | status | enable | disable 服务名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>启动，停止，查看状态，开启开机自启，关闭开机自启 系统服务： NetworkManager主网络服务 network副网络服务 firewalld防火墙服务 sshd，ssh服务（finalshell远程登录linux就是这个服务） 除了内置的服务以外，部分软件安装后也可以使用systemctl进行控制</p><h2 id="ln命令创建软链接" tabindex="-1"><a class="header-anchor" href="#ln命令创建软链接"><span>ln命令创建软链接</span></a></h2><p>在系统中创建软链接，可以将文件，文件夹链接到其他位置，类似windows的快捷方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ln -s 参数1 参数2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-s：创建软链接 参数1：被链接的文件或文件夹 参数2：要链接去的目的地</p><p>示例：</p><div class="language-把home目录下test文件夹中的f0.cpp软连接到home文件夹中 line-numbers-mode" data-highlighter="shiki" data-ext="把home目录下test文件夹中的f0.cpp软连接到home文件夹中" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ln -s ~/test/f0.cpp ~/</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="日期和时区" tabindex="-1"><a class="header-anchor" href="#日期和时区"><span>日期和时区</span></a></h2><p>date命令查看系统时间</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>date [-d] [+格式化字符串-格式化字符串]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-d：按照给定的字符串显示日期，一般用于日期计算 格式化字符串：通过特定的字符串标记来控制显示的日期格式</p><table><thead><tr><th>格式化字符串</th><th>作用</th></tr></thead><tbody><tr><td>%Y</td><td>年</td></tr><tr><td>%y</td><td>年份后两位数字（00~99）</td></tr><tr><td>%M</td><td>月份（01~12）</td></tr><tr><td>%d</td><td>日（01~31）</td></tr><tr><td>%H</td><td>小时（00~23）</td></tr><tr><td>%M</td><td>分钟（00~59）</td></tr><tr><td>%S</td><td>秒（00~60）</td></tr><tr><td>%s</td><td>自1970-01-01 00:00:00 UTC 到现在的秒数</td></tr></tbody></table><h2 id="ip地址和主机名" tabindex="-1"><a class="header-anchor" href="#ip地址和主机名"><span>IP地址和主机名</span></a></h2><p>每一台联网的电脑都会有一个地址，用于和其他计算机进行通讯 IPv4地址格式：a.b.c.d 其中abcd表示0~255的数字 可以通过ifconfig查看本机ip地址 inet就是ip地址</p><p><strong>特殊的ip地址</strong></p><table><thead><tr><th>ip地址</th><th>作用</th></tr></thead><tbody><tr><td>127.0.0.1</td><td>指代本机</td></tr><tr><td>0.0.0.0</td><td>可以用于指代本机，也可以在端口绑定中用来确定绑定关系，在一些ip地址限制中表示所有ip的意思，如放行规则设置为0.0.0.0表示允许任意ip访问</td></tr><tr><td>查看主机名</td><td></td></tr><tr><td>hostname命令</td><td></td></tr><tr><td>修改主机名（需要root）</td><td></td></tr><tr><td>hostnamectl set-hostname 主机名,修改主机名</td><td></td></tr></tbody></table><p><strong>配置主机名和ip地址的映射</strong> 本机记录 Windows：C:\\Windows\\System32\\drivers\\etc\\hosts 在文件末尾加上：ip地址 主机名 Linux：/etc/hosts</p><h2 id="下载和网络请求" tabindex="-1"><a class="header-anchor" href="#下载和网络请求"><span>下载和网络请求</span></a></h2><h3 id="ping" tabindex="-1"><a class="header-anchor" href="#ping"><span>ping</span></a></h3><p>可以通过ping命令，检查指定的网络服务器是否是可联通状态</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ping [-c num] ip或主机名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-C：检查的次数，不使用-c选项，将无限次数持续检查</p><h3 id="wget" tabindex="-1"><a class="header-anchor" href="#wget"><span>wget</span></a></h3><p>wget是非交互式的文件下载器，可以在命令行内下载网络文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>wget [-b] url</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-b：可选，后台下载，会将日志写入到当前工作目录的wget-log文件</p><p>无论下载成功不成功都会生成文件，如果不清理下次再下载就会提示已经下载过了</p><h3 id="curl" tabindex="-1"><a class="header-anchor" href="#curl"><span>curl</span></a></h3><p>curl可以发送http网络请求，可用于下载文件、获取信息等</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>curl [-O] url</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-O：用于下载文件，当url是下载链接时，可以使用此选项保存文件<br> url：要发起请求的网络地址</p><h2 id="端口" tabindex="-1"><a class="header-anchor" href="#端口"><span>端口</span></a></h2><p>物理端口：又可称之为接口，是可见的端口，如USB接口，RJ45网口，HDMI端口等<br> 虚拟端口：是指计算机内部的端口，是不可见的，用来操作系统和外部进行交互使用的</p><p>计算机程序之间的通讯，通过IP只能锁定计算机，但是无法锁定具体的程序。 通过端口可以锁定计算机上具体的程序，确保程序之间进行沟通<br> Linux系统可以支持65535个端口，这6万多个端口分为3类进行使用:</p><ul><li>公认端口：1~1023，通常用于一些系统内置或知名程序的预留使用，如SSH服务的22端口，HTTPS服务的443端，非特殊需要，不要占用这个范围的端口</li><li>注册端口：1024~49151，通常可以随意使用，用于松散的绑定一些程序\\服务</li><li>动态端口：49152~65535，通常不会固定绑定程序，而是当程序对外进行网络链接时，用于临时使用。</li></ul><h3 id="查看端口的占用情况" tabindex="-1"><a class="header-anchor" href="#查看端口的占用情况"><span>查看端口的占用情况</span></a></h3><p>使用nmap命令<br> 安装nmap: yum-y install nmap</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>nmap 被查看的IP地址</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="查看指定端口的占用情况" tabindex="-1"><a class="header-anchor" href="#查看指定端口的占用情况"><span>查看指定端口的占用情况</span></a></h3><p>可以通过netstat命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>netstat-anp|grep 端口号</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>安装netstat: yum -y install net-tools<br> 可以和管道符+grep配合使用</p><h2 id="进程" tabindex="-1"><a class="header-anchor" href="#进程"><span>进程</span></a></h2><p>程序运行在操作系统中，是被操作系统所管理的。<br> 为管理运行的程序，每一个程序在运行的时候，便被操作系统注册为系统中的一个：进程<br> 并会为每一个进程都分配一个独有的：进程ID（进程号）</p><h3 id="查看linux系统中的进程信息" tabindex="-1"><a class="header-anchor" href="#查看linux系统中的进程信息"><span>查看Linux系统中的进程信息</span></a></h3><p>可以通过ps命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ps [-e-f]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-e：显示出全部的进程<br> -f：以完全格式化的形式展示信息（展示全部信息）<br> 一般来说，固定用法就是：ps-ef列出全部进程的全部信息</p><table><thead><tr><th>符号</th><th>代表的含义</th></tr></thead><tbody><tr><td>UID</td><td>进程所属的用户ID（启动此进程的用户的id）</td></tr><tr><td>PID</td><td>进程的进程号ID</td></tr><tr><td>PPID</td><td>进程的父ID（启动此进程的其它进程）</td></tr><tr><td>C</td><td>此进程的CPU占用率（百分比）</td></tr><tr><td>STIME</td><td>进程的启动时间</td></tr><tr><td>TTY</td><td>启动此进程的终端序号，如显示？，表示非终端启动</td></tr><tr><td>TIME</td><td>进程占用CPU的时间</td></tr><tr><td>CMD</td><td>进程对应的名称或启动路径或启动命令</td></tr></tbody></table><h3 id="结束进程" tabindex="-1"><a class="header-anchor" href="#结束进程"><span>结束进程</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>kill [-9] 进程ID</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-9：表示强制关闭进程。<br> 不使用此选项会向进程发送信号要求其关闭，但是否关闭看进程自身的处理机制。</p><h3 id="查看任务管理器" tabindex="-1"><a class="header-anchor" href="#查看任务管理器"><span>查看任务管理器</span></a></h3><p>可以通过top命令查看CPU、内存使用情况，类似Windows的任务管理器默认每5秒刷新一次，语法：直接输入top即可，按q或ctrl+c退出<br> top命令也支持选项：</p><table><thead><tr><th>选项</th><th>功能</th></tr></thead><tbody><tr><td>-p 进程id</td><td>只显示某个进程的信息</td></tr><tr><td>-d 秒数</td><td>设置刷新时间，默认是5s</td></tr><tr><td>-c</td><td>显示产生进程的完整命令，默认是进程名</td></tr><tr><td>-n 次数</td><td>指定刷新次数，比如top -n 3，刷新输出3次后退出</td></tr><tr><td>-b</td><td>以非交互非全屏模式运行，以批次的方式执行top，一般配合-n指定输出几次统计信息，将输出重定向到指定文件，比如top-b-n 3&gt;/tmp/top.tmp</td></tr><tr><td>-i</td><td>不显示任何闲置（idle）或无用（zombie）的进程</td></tr><tr><td>-u 用户名</td><td>查找特定用户启动的进程</td></tr></tbody></table><p>当top以交互式运行（非-b选项启动），可以用以下交互式命令进行控制</p><table><thead><tr><th>按键</th><th>功能</th></tr></thead><tbody><tr><td>h</td><td>按下h键，会显示帮助画面</td></tr><tr><td>c</td><td>按下c键，会显示产生进程的完整命令，等同于-c参数，再次按下c键，变为默认显示</td></tr><tr><td>f</td><td>按下f键，可以选择需要展示的项目</td></tr><tr><td>M</td><td>按下M键，根据驻留内存大小（RES）排序</td></tr><tr><td>P</td><td>按下P键，根据CPU使用百分比大小进行排序</td></tr><tr><td>T</td><td>按下T键，根据时间/累计时间进行排序</td></tr><tr><td>E</td><td>按下E键，切换顶部内存显示单位</td></tr><tr><td>e</td><td>按下e键，切换进程内存显示单位</td></tr><tr><td>l</td><td>按下l键，切换显示平均负载和启动时间信息。</td></tr><tr><td>i</td><td>按下i键，不显示闲置或无用的进程，等同于-i参数，再次按下，变为默认显示</td></tr><tr><td>t</td><td>按下t键，切换显示CPU状态信息</td></tr><tr><td>m</td><td>按下m键，切换显示内存信息</td></tr></tbody></table><h4 id="内容详解" tabindex="-1"><a class="header-anchor" href="#内容详解"><span>内容详解</span></a></h4><ol><li>第一行 ![[Clip_2024-03-13_12-34-50.png]]</li></ol><ul><li>top：命令名称</li><li>14:39:58：当前系统时间</li><li>up 6 min：启动时间</li><li>users：几个用户登录</li><li>load：1、5、15分钟负载（后面加average是平均负载）</li></ul><ol start="2"><li>第二行</li></ol><p>![[Clip_2024-03-13_12-35-17.png]]</p><ul><li>Tasks：总进程数</li><li>1 running：运行进程数</li><li>174 sleeping：睡眠进程数</li><li>stopped：停止进程数</li><li>zombie：僵尸进程数</li></ul><ol start="3"><li>第三行</li></ol><p>![[Clip_2024-03-13_12-35-33.png]]</p><ul><li>%Cpu(s)：CPU使用率</li><li>us：用户CPU使用率</li><li>sy：系统CPU使用率</li><li>ni：高优先级进程占用CPU时间百分比</li><li>id：空闲CPU率</li><li>wa：IO等待CPU占用率</li><li>hi：CPU硬件中断率</li><li>si：CPU软件中断率</li><li>st：强制等待占用CPU率</li></ul><ol start="4"><li>第四行</li></ol><p>![[Clip_2024-03-13_12-35-47.png]]</p><ul><li>KiB Mem：物理内存</li><li>total：总量</li><li>free：空闲</li><li>used：使用</li><li>buff/cache：buff和cache占用</li><li>KiB Swap：虚拟内存（交换空间）</li></ul><p>![[Clip_2024-03-13_12-45-28.png]] PID：进程id USER：进程所属用户 PR：进程优先级，越小越高 NI：负值表示高优先级，正表示低优先级 VIRT：进程使用虚拟内存，单位KB RES：进程使用物理内存，单位KB SHR：进程使用共享内存，单位KB S：进程状态（S休眠，R运行，Z僵死状态，N负数优先级，I空闲状态） %CPU：进程占用CPU率 %MEM：进程占用内存率 TIME+：进程使用CPU时间总计，单位10毫秒 COMMAND：进程的命令或名称或程序文件路径</p><h3 id="查看硬盘使用情况" tabindex="-1"><a class="header-anchor" href="#查看硬盘使用情况"><span>查看硬盘使用情况</span></a></h3><p>使用df命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>df [-h]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-h：以更加人性化的单位显示</p><h3 id="查看cpu、磁盘的相关信息" tabindex="-1"><a class="header-anchor" href="#查看cpu、磁盘的相关信息"><span>查看CPU、磁盘的相关信息</span></a></h3><p>使用iostat</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>iostat [-x] [num1] [num2]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-X：显示更多信息<br> num1：数字，刷新间隔 num2：数字，刷新几次</p><blockquote><p>[!tip] 该设备每秒的传输次数 （Indicate the number of transfers per second that were issued to the device.)。“一次传输“意思是“一次i/o请求&quot;。多个逻辑请求可能会被合并为“一次i/o请求&quot;。“一次传输“请求的大小是未知的。</p></blockquote><h4 id="使用-x选项显示更多信息解读" tabindex="-1"><a class="header-anchor" href="#使用-x选项显示更多信息解读"><span>使用-x选项显示更多信息解读</span></a></h4><table><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>rrqm/s</td><td>每秒这个设备相关的读取请求有多少被Merge了（当系统调用需要读取数据的时候，VFS将请求发到各个FS,如果FS发现不同的读取请求读取的是相同Block的数据，FS会将这个请求合并Merge，提高IO利用率，避免重复调用）</td></tr><tr><td>wrqm/s</td><td>每秒这个设备相关的写入请求有多少被Merge了</td></tr><tr><td>rsec/s</td><td>每秒读取的扇区数sectors</td></tr><tr><td>wsec/</td><td>每秒写入的扇区数</td></tr><tr><td>rKB/s</td><td>每秒发送到设备的读取请求数</td></tr><tr><td>wKB/s</td><td>每秒发送到设备的写入请求数</td></tr><tr><td>avgrq-sz</td><td>平均请求扇区的大小</td></tr><tr><td>avgqu-sz</td><td>平均请求队列的长度。毫无凝问，队列长度越短越好。</td></tr><tr><td>await</td><td>每一个I0请求的处理的平均时间(单位是微秒毫秒）。</td></tr><tr><td>svctm</td><td>表示平均每次设备I/0操作的服务时间（以毫秒为单位）</td></tr><tr><td>%util</td><td>磁盘利用率</td></tr></tbody></table><h3 id="网络状态监控" tabindex="-1"><a class="header-anchor" href="#网络状态监控"><span>网络状态监控</span></a></h3><p>可以使用sar命令查看网络的相关统计（sar命令非常复杂，这里仅简单用于统计网络)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span> sar -n DEV num1 num2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-n：查看网络，DEV表示查看网络接口<br> num1：刷新间隔（不填就查看一次结束） num2：查看次数（不填无限次数）</p><table><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>IFACE</td><td>本地网卡接口的名称</td></tr><tr><td>rxpck/s</td><td>每秒钟接受的数据包</td></tr><tr><td>txpck/s</td><td>每秒钟发送的数据包</td></tr><tr><td>rxKB/S</td><td>每秒钟接受的数据包大小，单位为KB</td></tr><tr><td>txKB/S</td><td>每秒钟发送的数据包大小，单位为KB</td></tr><tr><td>rxcmp/s</td><td>每秒钟接受的压缩数据包</td></tr><tr><td>txcmp/s</td><td>每秒钟发送的压缩包</td></tr><tr><td>rxmcst/s</td><td>每秒钟接收的多播数据包</td></tr></tbody></table><h3 id="环境变量" tabindex="-1"><a class="header-anchor" href="#环境变量"><span>环境变量</span></a></h3><p>env命令查看当前系统记录的环境变量 环境变量是一种keyvalue型结构</p><p>$符号用于取变量的值 通过和echo命令组合来查看环境变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo $ PATH</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="设置环境变量" tabindex="-1"><a class="header-anchor" href="#设置环境变量"><span>设置环境变量</span></a></h4><p><strong>临时设置</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export 变量名=变量值</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>永久生效</strong> 针对当前用户，将命令写在~/bashrc文件中 针对所有用户生效，将命令写在/etc/profile中 然后通过命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>source 配置的文件</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使更改立即生效</p><h2 id="文件上传和下载" tabindex="-1"><a class="header-anchor" href="#文件上传和下载"><span>文件上传和下载</span></a></h2><p>可以通过shell工具拖拽操作 也可以通过rz，sx命令进行 通过：yum -y install lrzsz安装 rs上传直接输入rz sz下载</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sz 要下载的文件</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>文件会自动下载到桌面的fsdownload文件夹中</p><h2 id="压缩和解压" tabindex="-1"><a class="header-anchor" href="#压缩和解压"><span>压缩和解压</span></a></h2><p>zip格式：Linux、Windows、MacOS，常用 7zip: Windows系统常用 rar:Windows系统常用 tar:Linux、MacOS常用 gzip:Linux、MacOS常用</p><p>.tar，称之为tarball，归档文件，即简单的将文件组装到一个.tar的文件内，并没有太多文件体积的减少，仅仅是简单 的封装 .gz，也常见为.tar.gz，gzip格式压缩文件，即使用gzip压缩算法将文件压缩到一个文件内，可以极大的减少压缩后的体积 针对这两种格式，使用tar命令均可以进行压缩和解压缩的操作</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tar [-c -v -x -f -z -C] 参数1 参数2... 参数N</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>参数1：压缩后文件的名称 其他参数都是要压缩的文件名</p><table><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>-c</td><td>创建压缩文件，用于压缩模式</td></tr><tr><td>-v</td><td>显示压缩、解压过程，用于查看进度</td></tr><tr><td>-×</td><td>解压模式</td></tr><tr><td>-f</td><td>要创建的文件，或要解压的文件，-f选项必须在所有选项中位置处于最后一个</td></tr><tr><td>-z</td><td>gzip模式，不使用-z就是普通的tarball格式</td></tr><tr><td>-C</td><td>选择解压的目的地，用于解压模式</td></tr></tbody></table><p>-z选项如果使用的话，一般处于选项位第一个 -f选项，必须在选项位最后一个</p><h3 id="zip命令-压缩文件为zip压缩包" tabindex="-1"><a class="header-anchor" href="#zip命令-压缩文件为zip压缩包"><span>zip命令，压缩文件为zip压缩包</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>zip [-r] 参数1 参数2 ... 参数N</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-r，被压缩的包含文件夹的时候，需要使用-r选项，和rm、cp等命令的-r效果一致</p><p>使用unzip命令，可以方便的解压zip压缩包</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unzip [-d] 参数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-d，指定要解压去的位置，同tar的-C选项 参数，被解压的zip压缩包文件</p><h1 id="命令行参数" tabindex="-1"><a class="header-anchor" href="#命令行参数"><span>命令行参数</span></a></h1><p>main函数带参表示要执行命令行参数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main(int argc,char* argv[]){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>argc：参数个数，包括可执行文件名 argv：参数字符串数组 数组长度为argc</p><p>argv[0]~argv[argc-1]指向命令行各输入项的字符串首地址 argv[argc]存放NULL表示字符串结尾</p><h1 id="错误代码" tabindex="-1"><a class="header-anchor" href="#错误代码"><span>错误代码</span></a></h1><p>c语言文件中头文件&lt; errno.h&gt; 输出错误代码：perror(&quot;fopen&quot;);</p><h1 id="输入输出" tabindex="-1"><a class="header-anchor" href="#输入输出"><span>输入输出</span></a></h1><p>标准io有用户缓冲区，文件io没有 使用内核缓冲技术</p><h1 id="输出重定向" tabindex="-1"><a class="header-anchor" href="#输出重定向"><span>输出重定向</span></a></h1><p>使用&gt;操作符 将内容指向文件即可将输出从屏幕重定向到文件中</p><p>&gt;&gt;操作符将内容重定向追加到文件中</p><h1 id="查看进程树" tabindex="-1"><a class="header-anchor" href="#查看进程树"><span>查看进程树</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pstree -p</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="以树状形式查看目录" tabindex="-1"><a class="header-anchor" href="#以树状形式查看目录"><span>以树状形式查看目录</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tree [-L number] 目录名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>若不指定目录名默认显示当前目录中的文件 -L：后面加数字几就只显示几层子目录（如果子目录中文件太多全部显示出来会耗费很长事件）</p><h1 id="压缩文件" tabindex="-1"><a class="header-anchor" href="#压缩文件"><span>压缩文件</span></a></h1><h2 id="tar格式" tabindex="-1"><a class="header-anchor" href="#tar格式"><span>tar格式</span></a></h2><p>linux中提供了一个tar命令，但这个命令只能打包文件不能压缩；其中系统也默认提供了两个压缩工具：gzip和bzip2，但这两个工具只能压缩不能打包，而且压缩后源文件也没有了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tar [c/x/z/j/v/f] 文件名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>c</code>： 压缩文件</li><li><code>x</code>： 解压文件</li><li><code>z</code>： 使用<code>gzip</code>的方式进行文件压缩</li><li><code>j</code>： 使用<code>bzip2</code>的方式进行文件压缩</li><li><code>v</code>： 压缩过程中显示压缩信息, 可以省略不写</li><li><code>f</code>： 指定压缩包的名字 压缩好的文件并没有后缀名，建议在文件名后将压缩的信息写上 压缩使用 gzip 方式, 标准后缀格式为: .tar.gz<br> 压缩使用 bzip2 方式, 标准后缀格式为: .tar.bz2</li></ul><p>解压时要使用x参数，且用哪个工具压缩的就要用对应的工具解压（gzip、bzip2）</p><h2 id="zip格式" tabindex="-1"><a class="header-anchor" href="#zip格式"><span>zip格式</span></a></h2><p>linux里面没有默认提供的zip压缩工具需要自己下载</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sudo apt install zip    # 压缩  </span></span>
<span class="line"><span>sudo apt install unzip	# 解压缩</span></span>
<span class="line"><span>zip [-r]  压缩包名 要压缩的文件</span></span>
<span class="line"><span>unzip [-d]  要解压的文件</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用<code>zip</code>压缩目录需要注意一点, 必须要添加参数 <code>-r</code>, 这样才能将子目录中的文件一并压缩, 如果要压缩的文件中没有目录, 该参数就可以不写了。 另外使用<code>zip</code>压缩文件, 会自动生成文件后缀<code>.zip</code>, 因此就不需要额外指定了</p><p>解压缩时默认解压到当前目录，可以使用-d参数指定解压的目录</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unzip 要解压的文件 -d 目标目录</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="rar格式" tabindex="-1"><a class="header-anchor" href="#rar格式"><span>rar格式</span></a></h2><p><code>rar</code>这种压缩格式在Linux中并不常用, 这是Windows常用的压缩格式, 如果想要在Linux压缩和解压这种格式的文件需要额外安装对应的工具</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sudo apt install rar</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用<code>rar</code>压缩过程中的注意事项和<code>zip</code>是一样的, <code>如果压缩的是目录, 需要指定参 -r</code>, 如果只压缩文件就不需要添加了。压缩过程中<mark>需要使用参数 <code>a</code></mark>, (archive)压缩归档的意思。 <code>rar</code>工具在生成压缩包的时候也会自动添加后缀, 名字为<code>.rar</code>, 因此我们只需要指定压缩包的名字。</p><p>解压缩<code>.rar</code>格式的文件的时候, 可以使用 <code>rar</code>也可以使用<code>unrar</code>, 操作方式是一样的, -<mark>需要添加参数 <code>x</code></mark>, 默认是将压缩包内容释放到当前目录中, 如果要释放到指定目录直接指定解压目录名即可, 不需要使用任何参数。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>rar/unrar x 压缩包名字 解压目录</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="xz格式" tabindex="-1"><a class="header-anchor" href="#xz格式"><span>xz格式</span></a></h2><p><code>.xz</code>格式的文件压缩和解压缩都相对比较麻烦, 通过一个命令是完不成对应的操作的, 需要通过两步操作才行。并且操作过程中需要使用<code>tar</code>工具进行打包, 压缩使用的则是 <code>xz</code>工具。</p><ol><li>首先 将需要压缩的文件打包 <code>tar cvf xxx.tar files</code>（建议命名后加上.tar后缀）</li><li>然后再对打包文件进行压缩 <code>xz -z xxx.tar</code>, 这样我们就可以得到一个打包之后的压缩文件了。</li></ol><p>解压缩的步骤和压缩的步骤相反, 需要先解压缩, 然后将文件包中的文件释放出来。</p><ol><li>压缩包解压缩<code>xz -d xxx.tar.xz</code></li><li>将 xxx.tar 中的文件释放到当前目录 <code>tar xvf xxx.tar</code></li></ol><h2 id="命令别名" tabindex="-1"><a class="header-anchor" href="#命令别名"><span>命令别名</span></a></h2><p>打开用户家目录下的.bashrc文件后在里面配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vi ~/.bashrc</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,164)]))}const h=i(d,[["render",r]]),p=JSON.parse('{"path":"/base/linux/3/","title":"3 命令","lang":"zh-CN","frontmatter":{"title":"3 命令","createTime":"2025/06/18 20:42:46","permalink":"/base/linux/3/"},"readingTime":{"minutes":16.58,"words":4973},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/Linux/3 命令.md","headers":[]}');export{h as comp,p as data};
